// EMERGENCY STOP CHECK
// Must be the first code node in every workflow, right after the trigger.
// Checks the EMERGENCY_STOP environment variable. If true, sends a
// notification to Discord and halts the workflow (returns empty array).
//
// Referenced in: crisis.md, n8n-workflow-specs.md
// Variable: EMERGENCY_STOP (Settings > Variables)

const emergencyStop = $env.EMERGENCY_STOP;

if (emergencyStop === 'true' || emergencyStop === true) {
  const workflowName = $workflow.name || 'Unknown Workflow';
  const timestamp = new Date().toISOString();

  const discordUrl = $env.DISCORD_WEBHOOK_URL;
  if (discordUrl) {
    try {
      await fetch(discordUrl, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          content: `**EMERGENCY STOP ACTIVE** | Workflow "${workflowName}" halted at ${timestamp}. No content was published. Set EMERGENCY_STOP=false in n8n variables to resume.`
        })
      });
    } catch (e) {
      // Discord notification failed, but we still halt.
    }
  }

  return [];
}

return $input.all();

// PRE-POST EMERGENCY STOP CHECK
// Second check right before sending intel digest to Discord.
// Catches mid-execution activation of EMERGENCY_STOP.

const emergencyStop = $env.EMERGENCY_STOP;

if (emergencyStop === 'true' || emergencyStop === true) {
  return [];
}

return $input.all();

const competitorTweets = $('X: Competitor Tweets').first().json;
const mentions = $('X: VoidAI Mentions').first().json;
const sn106 = $('Taostats: SN106').first().json;

const digest = {
  competitor_tweets: competitorTweets?.data || [],
  competitor_count: competitorTweets?.data?.length || 0,
  voidai_mentions: mentions?.data || [],
  mention_count: mentions?.data?.length || 0,
  sn106_data: sn106 || {},
  generated_at: new Date().toISOString()
};

return [{ json: digest }];

const staticData = $getWorkflowStaticData('global');
if (!staticData.intel_digests) staticData.intel_digests = {};

const data = $input.first().json;
const date = new Date().toISOString().split('T')[0];
const dateDisplay = new Date().toLocaleDateString('en-US', {
  weekday: 'long', year: 'numeric', month: 'long', day: 'numeric',
  timeZone: 'America/New_York'
});

staticData.intel_digests[date] = {
  type: 'competitor-intel',
  status: 'collected',
  collected_at: new Date().toISOString(),
  data: {
    competitor_tweets: data.competitor_tweets,
    competitor_count: data.competitor_count,
    voidai_mentions: data.voidai_mentions,
    mention_count: data.mention_count,
    sn106_data: data.sn106_data
  }
};

// Cleanup: keep last 14 days
const keys = Object.keys(staticData.intel_digests).sort();
if (keys.length > 14) {
  keys.slice(0, keys.length - 14).forEach(k => delete staticData.intel_digests[k]);
}

return [{ json: {
  message: `**Competitor Intel Data Collected | ${dateDisplay}**\n\nCompetitor tweets found: ${data.competitor_count}\nVoidAI mentions found: ${data.mention_count}\n\nRaw data stored in workflow static data. Review in n8n execution log for details.`,
  date: dateDisplay,
  competitor_count: data.competitor_count,
  mention_count: data.mention_count
} }];

const data = $input.first().json;
const date = new Date().toISOString();

return [{ json: {
  status: 'dry_run',
  timestamp: date,
  message: 'Competitor monitor data collected but not delivered (DRY_RUN is not false)',
  competitor_count: data.competitor_count || 0,
  mention_count: data.mention_count || 0
} }];

